import React from 'react';

const AboutUs = () => {
  return (
    <div className="pt-24 min-h-screen bg-white">
      <div className="max-w-7xl mx-auto px-4 py-16">
        <h1 className="text-4xl font-bold text-blue-800 mb-6">About Hudson Manpower</h1>
        <p className="text-lg text-gray-700 leading-relaxed max-w-3xl">
          We are a premier global staffing and software solutions provider, 
          dedicated to bridging the gap between exceptional talent and leading industries. 
          With over a decade of experience, we specialize in delivering high-quality 
          manpower solutions.
        </p>
      </div>
    </div>
  );
};

export default AboutUs;
